select s.id, s.category_id, c.name as category_name, s.name, s.description, s.features, s.price, s.type, s.sales, s.image, s.cover, s.duration, s.status, s.create_time from service_item s left join service_category c on s.category_id = c.id
s.status = 1
and s.category_id = #{categoryId}
and s.type = #{type}
and (s.name like CONCAT('%', #{keyword}, '%') or s.description like CONCAT('%', #{keyword}, '%'))
order by s.price asc
order by s.price desc
order by s.sales desc
order by s.create_time desc
limit #{offset}, #{pageSize}

select count(*) from service_item s
s.status = 1
and s.category_id = #{categoryId}
and s.type = #{type}
and (s.name like CONCAT('%', #{keyword}, '%') or s.description like CONCAT('%', #{keyword}, '%'))
